"""Экспорт одного эксперимента в .docx с вставкой графиков."""from __future__ import annotationsimport iofrom pathlib import Pathfrom typing import Anyfrom docx import Documentfrom docx.shared import Inchesfrom matplotlib.backends.backend_agg import FigureCanvasAggfrom matplotlib.figure import Figurefrom ..core.types import ExperimentResultfrom ._provenance import filter_params, noise_params, signal_params_TABLE_STYLE = "Table Grid"def export_docx(result: ExperimentResult, path: str | Path) -> Path:    path = Path(path)    doc = Document()    doc.add_heading("Отчёт об эксперименте SAFR", level=1)    doc.add_paragraph(f"Время (UTC): {result.timestamp}")    doc.add_paragraph(f"Сигнал: {result.signal_name}")    doc.add_paragraph(f"Шум: {result.noise_name}")    doc.add_paragraph(f"Фильтр: {result.filter_name}")    doc.add_heading("Параметры эксперимента", level=2)    _add_kv_table(doc, "Сигнал", signal_params(result))    _add_kv_table(doc, "Шум", noise_params(result))    _add_kv_table(doc, "Фильтр", filter_params(result))    doc.add_heading("Метрики качества", level=2)    m = result.metrics    _add_plain_table(doc, [        ("MSE", f"{m.mse:.6e}"),        ("RMSE", f"{m.rmse:.6e}"),        ("SNR до, дБ", f"{m.snr_before_db:.3f}"),        ("SNR после, дБ", f"{m.snr_after_db:.3f}"),        ("Улучшение SNR, дБ", f"{m.snr_improvement_db:+.3f}"),        ("Корреляция", f"{m.correlation:.4f}"),    ])    doc.add_heading("Графики", level=2)    try:        png = _render_plot_png(result)        doc.add_picture(io.BytesIO(png), width=Inches(6.0))    except Exception as e:        doc.add_paragraph(f"(Не удалось вставить графики: {type(e).__name__}: {e})")    doc.save(path)    return pathdef _render_plot_png(result: ExperimentResult) -> bytes:    fig = Figure(figsize=(7.0, 5.0), tight_layout=True)    FigureCanvasAgg(fig)    ax1 = fig.add_subplot(3, 1, 1)    ax1.plot(result.clean.t, result.clean.x, linewidth=0.9)    ax1.set_title(f"Исходный: {result.signal_name}", fontsize=10)    ax1.grid(True, alpha=0.3)    ax2 = fig.add_subplot(3, 1, 2, sharex=ax1)    ax2.plot(result.noisy.t, result.noisy.x, linewidth=0.9, color="tab:orange")    ax2.set_title(f"Зашумлённый: {result.noise_name}", fontsize=10)    ax2.grid(True, alpha=0.3)    ax3 = fig.add_subplot(3, 1, 3, sharex=ax1)    ax3.plot(result.restored.t, result.restored.x, linewidth=0.9, color="tab:green")    ax3.set_title(f"Восстановленный: {result.filter_name}", fontsize=10)    ax3.set_xlabel("t, с")    ax3.grid(True, alpha=0.3)    buf = io.BytesIO()    fig.savefig(buf, format="png", dpi=120)    buf.seek(0)    return buf.getvalue()def _add_kv_table(doc, title: str, params: dict[str, Any]) -> None:    doc.add_heading(title, level=3)    if not params:        doc.add_paragraph("(нет параметров)")        return    table = doc.add_table(rows=1, cols=2)    table.style = _TABLE_STYLE    hdr = table.rows[0].cells    hdr[0].text = "Параметр"    hdr[1].text = "Значение"    for k, v in params.items():        row = table.add_row().cells        row[0].text = str(k)        row[1].text = _fmt_value(v)def _add_plain_table(doc, rows: list[tuple[str, str]]) -> None:    table = doc.add_table(rows=1, cols=2)    table.style = _TABLE_STYLE    hdr = table.rows[0].cells    hdr[0].text = "Метрика"    hdr[1].text = "Значение"    for k, v in rows:        r = table.add_row().cells        r[0].text = str(k)        r[1].text = str(v)def _fmt_value(v: Any) -> str:    if isinstance(v, float):        return f"{v:.6g}"    return str(v)